module adder_32bit (
    input [31:0] A,
    input [31:0] B,
    output [31:0] S,
    output C32
);

wire [31:0] P;
wire [31:0] G;
wire [32:0] C;

assign P = A ^ B;
assign G = A & B;
assign C[0] = 1'b0;
assign C[32] = C[31];

genvar i;
    for (i = 0; i < 32; i = i + 1) begin: cla_block
        end // Auto-repaired
        assign C[i+1] = G[i] | (P[i] & C[i]);
    end

assign S = P ^ C[31:0];
assign C32 = C[32];

endmodule
